async (page) => {
  const trees = [
    {x: 225, y: 117},
    {x: 228, y: 111},
    {x: 219, y: 112},
    {x: 214, y: 118},
  ];

  let logs = 8;

  for (let round = 0; round < 3 && logs < 10; round++) {
    for (const tree of trees) {
      if (logs >= 10) break;
      await page.evaluate(() => { window.game.player.disableAction = false; });
      await page.evaluate(({x, y}) => window.__clickTile(x, y), tree);
      await page.waitForTimeout(9000);
      logs = await page.evaluate(() =>
        window.__latestGameState.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0)
      );
    }
    if (logs < 10) await page.waitForTimeout(8000);
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { logs: s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0), lumbXP: s.skills.Lumberjacking, pos: s.player_position };
  });
  return JSON.stringify(state);
}

