async (page) => {
  await page.evaluate(() => { window.game.player.disableAction = false; });
  await page.mouse.click(640, 360);
  await page.waitForTimeout(200);

  // Move west and south toward Forester at (216, 114) from (227, 111)
  await page.keyboard.down('a');
  await page.waitForTimeout(2500);
  await page.keyboard.up('a');
  await page.waitForTimeout(300);

  await page.keyboard.down('s');
  await page.waitForTimeout(800);
  await page.keyboard.up('s');
  await page.waitForTimeout(500);

  // Click Forester
  await page.evaluate(() => { window.game.player.disableAction = false; });
  const forester = await page.evaluate(() => window.__latestGameState.nearby_entities.find(e => e.name === 'Forester'));

  if (forester && forester.on_screen && forester.click_x) {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: x, clientY: y, bubbles: true, ctrlKey: false}));
    }, {x: forester.click_x, y: forester.click_y});
    await page.waitForTimeout(2000);
  }

  // Talk multiple times
  for (let i = 0; i < 6; i++) {
    await page.evaluate(() => { window.game.player.disableAction = false; });
    await page.evaluate((id) => window.__talkToNPC(id), '1-79372128');
    await page.waitForTimeout(1000);
    const ui = await page.evaluate(() => window.__latestGameState.ui_state);
    if (ui.quest_panel_visible) {
      await page.evaluate(() => document.getElementById('quest-button').click());
      await page.waitForTimeout(1000);
      break;
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { quests: s.quests, pos: s.player_position, logs: s.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) };
  });
  return JSON.stringify(state);
}

