async (page) => {
  // Collect from multiple bushes — Blueberry Bushes at (203,120) and (222,126)
  const bushes = [
    {x: 203, y: 120},
    {x: 222, y: 126},
  ];

  for (const bush of bushes) {
    await page.evaluate(() => { window.game.player.disableAction = false; });
    // Move adjacent and harvest
    const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), bush);
    await page.waitForTimeout(5000);

    // Find and click the bush entity
    await page.evaluate(() => { window.game.player.disableAction = false; });
    const entity = await page.evaluate(({tx, ty}) => {
      const s = window.__latestGameState;
      return s.nearby_entities.find(e => e.type === 12 && Math.abs(e.x - tx) <= 2 && Math.abs(e.y - ty) <= 2);
    }, {tx: bush.x, ty: bush.y});

    if (entity) {
      await page.evaluate((id) => window.__talkToNPC(id), entity.id);
      await page.waitForTimeout(5000);
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { inv: s.inventory.map(i => ({name: i.name, count: i.count})), foraging: s.skills.Foraging, pos: s.player_position };
  });
  return JSON.stringify(state);
}

