async (page) => {
  // Move closer to Dying Soldier - multi-step navigation
  for (let i = 0; i < 3; i++) {
    await page.evaluate(({x, y}) => window.__moveTo(x, y), {x: 288, y: 134});
    await page.waitForTimeout(8000);

    const pos = await page.evaluate(() => {
      const s = window.__latestGameState;
      return { pos: s.player_position, hp: s.player_stats.hp, isDead: s.ui_state.is_dead,
               dyingSoldier: s.nearby_entities.find(e => e.name === 'Dying Soldier') };
    });

    if (pos.isDead) return 'DIED';
    if (pos.dyingSoldier && pos.dyingSoldier.distance <= 2) {
      return JSON.stringify({ reached: true, pos: pos.pos, soldier: pos.dyingSoldier });
    }

    // If HP too low, don't navigate through Sneks
    if (pos.hp / 639 < 0.4) {
      return JSON.stringify({ lowHp: true, pos: pos.pos, hp: pos.hp });
    }
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, hp: s.player_stats.hp,
             dyingSoldier: s.nearby_entities.find(e => e.name === 'Dying Soldier') };
  });
  return JSON.stringify(finalState);
}

