async (page) => {
  // Eat all food to recover HP
  await page.evaluate(() => {
    const inv = window.__latestGameState.inventory;
    for (const item of inv) {
      if (item.edible) {
        window.game.menu.getInventory().selectEdible(item.slot);
      }
    }
  });
  await page.waitForTimeout(2000);

  // Kill Desert Scorpion
  await page.evaluate(() => {
    window.game.input.keyMovement = false;
    window.game.player.disableAction = false;
    window.game.player.joystickMovement = false;
    const p = window.game.player;
    const grid = window.game.entities.grids.renderingGrid;
    const px = p.gridX, py = p.gridY;
    let nearest = null, nearestDist = 999;
    for (let dy = -5; dy <= 5; dy++) {
      for (let dx = -5; dx <= 5; dx++) {
        const gx = px + dx, gy = py + dy;
        if (!grid[gy] || !grid[gy][gx]) continue;
        for (const k of Object.keys(grid[gy][gx])) {
          const ent = grid[gy][gx][k];
          if (ent && ent !== p && ent.isMob && ent.isMob()) {
            const d = Math.abs(dx) + Math.abs(dy);
            if (d < nearestDist) { nearest = {gx, gy, d}; nearestDist = d; }
          }
        }
      }
    }
    if (nearest) window.game.input.move({ gridX: nearest.gx, gridY: nearest.gy }, false);
  });
  await page.waitForTimeout(13000);

  // Now navigate north to escape
  await page.mouse.click(640, 360);
  await page.waitForTimeout(200);
  await page.keyboard.down('w');
  await page.waitForTimeout(10000);
  await page.keyboard.up('w');
  await page.waitForTimeout(500);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, hp: s.player_stats.hp, maxHp: s.player_stats.max_hp, isDead: s.ui_state.is_dead };
  });
  return JSON.stringify(state);
}
